  <div class="es">
    <svg viewBox="0 0 700 440" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
      <text x="350" y="26" fill="#fafafa" font-size="16" font-weight="700" text-anchor="middle" font-family="sans-serif">Los coeficientes de correlación tienen fecha de caducidad</text>
      <text x="350" y="46" fill="#a1a1aa" font-size="13" text-anchor="middle" font-family="sans-serif">Oscilaciones anuales de la correlación BTC-S&amp;P 500 y BTC-Oro</text>
      <line x1="60" y1="80" x2="60" y2="330" stroke="#3f3f46" stroke-width="1"/>
      <line x1="60" y1="205" x2="660" y2="205" stroke="#3f3f46" stroke-width="1" stroke-dasharray="3,3"/>
